<template>
  <div>
    <v-main class="main-content">
      <v-container fluid>
        <v-row justify="center">
          <v-col cols="12" sm="8" md="6">
            <!-- Dynamic Form Fields Section -->

            <!-- Input Fields: Dynamically Generated Text Fields -->
            <div v-if="dynamicInputs.length > 0">
              <div v-for="(input, index) in dynamicInputs" :key="input.id" class="input-field-container">
                <v-text-field
                  v-model="input.value"
                  :label="input.label"
                  clearable
                  variant="solo"
                  :error="inputErrors[index]" 
                  :error-messages="inputErrors[index] ? 'This field is required.' : ''"
                />
                <!-- Hyperlink Button/Icon -->
                <v-btn
                  v-if="input.hyperlink"
                  icon
                  @click="navigateTo(input.hyperlink.url)"
                  :title="input.hyperlink.label"
                  class="hyperlink-button"
                >
                  <v-icon>mdi-link</v-icon>
                </v-btn>
              </div>
            </div>

            <!-- Dropdown Menus: Dynamically Generated Dropdown Selectors -->
            <div v-if="dropdownMenus.length > 0">
              <div v-for="dropdown in dropdownMenus" :key="dropdown.id" class="dropdown-field-container">
                <v-select
                  v-model="dropdown.selectedOption"
                  :items="dropdown.options ? dropdown.options.map(option => option.label) : []"
                  :label="formatDropdownLabel(dropdown.id)"  
                  variant="solo"
                  clearable
                />
                <!-- Hyperlink Button/Icon -->
                <v-btn
                  v-if="dropdown.hyperlink"
                  icon
                  @click="navigateTo(dropdown.hyperlink.url)"
                  :title="dropdown.hyperlink.label"
                  class="hyperlink-button"
                >
                  <v-icon>mdi-link</v-icon>
                </v-btn>
              </div>
            </div>

            <!-- Date Pickers: Dynamically Generated Date Selectors with Validation -->
            <div v-if="dynamicDateFields.length > 0">
              <div v-for="(dateField, index) in dynamicDateFields" :key="dateField.id" class="date-field-container">
                <!-- Date Input Field: Opens Date Picker on Focus -->
                <v-text-field
                  v-model="dateField.value"
                  :label="formatDateLabel(dateField.id)"
                  @focus="showDatePickerForField(dateField, index)"
                  readonly
                  :error="dateErrors[index]"  
                  :error-messages="dateErrors[index] ? 'Please select a date.' : ''" 
                />
                <!-- Hyperlink Button/Icon -->
                <v-btn
                  v-if="dateField.hyperlink"
                  icon
                  @click="navigateTo(dateField.hyperlink.url)"
                  :title="dateField.hyperlink.label"
                  class="hyperlink-button"
                >
                  <v-icon>mdi-link</v-icon>
                </v-btn>
                
                <!-- Date Picker Component: Displays Calendar for Date Selection -->
                <v-date-picker
                  v-if="dateField.showDatePicker"
                  v-model="dateField.selectedDate"
                  @update:model-value="(newDate) => updateDynamicDateField(dateField, index, newDate)"
                  color="blue-grey-lighten-1"
                  elevation="24"
                  :rounded="'30px'"
                  style="width: 810px;"
                />
              </div>
            </div>

            <!-- Navigation Button Section -->

            <!-- Next Button with Tooltip: Proceeds to Next Step if All Fields Are Filled -->
            <v-tooltip bottom>
              <template v-slot:activator="{ on }">
                <v-btn
                  @click="navigateToDynamicTablePage"
                  :disabled="!allFieldsFilled"
                  v-on="on"
                >
                  Next
                </v-btn>
              </template>
              <span v-if="!allFieldsFilled">Please fill in all fields before proceeding.</span>
            </v-tooltip>
          </v-col>
        </v-row>
      </v-container>
    </v-main>
  </div>
</template>

<script>
import { ref, onMounted, computed } from 'vue';
import { useRouter, onBeforeRouteLeave } from 'vue-router';
import { useStore } from 'vuex';
import { format } from 'date-fns';
import { fetchTemplateAndParseData, fetchDateFields } from '@/utils/utility.js';
import axios from 'axios';

export default {
  setup() {
    const router = useRouter();
    const store = useStore();

    // State Variables and Refs
    const inputErrors = ref({});
    const dropdownErrors = ref({});
    const dateErrors = ref({});

    const dynamicInputs = ref([]);
    const dropdownMenus = ref([]);
    const dynamicDateFields = ref([]);

    // Computed Property for Validation
    const allFieldsFilled = computed(() => {
      const inputsFilled = dynamicInputs.value.every((input, index) => {
        const filled = input.value && input.value.trim() !== '';
        inputErrors.value[index] = !filled;
        return filled;
      });

      const dropdownsFilled = dropdownMenus.value.every((dropdown, index) => {
        const filled = dropdown.selectedOption && dropdown.selectedOption.trim() !== '';
        dropdownErrors.value[index] = !filled;
        return filled;
      });

      const datesFilled = dynamicDateFields.value.every((dateField, index) => {
        const filled = dateField.value && dateField.value.trim() !== '';
        dateErrors.value[index] = !filled;
        return filled;
      });

      return inputsFilled && dropdownsFilled && datesFilled;
    });

    // Utility Functions
    const formatDropdownLabel = (dropdownId) => {
      return dropdownId.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
    };

    const formatDateLabel = (dateFieldId) => {
      return dateFieldId.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
    };

    const getYear = (dateInput) => {
      let date = new Date(dateInput);
      return date.getFullYear();
    };

    const getQuarter = (dateInput) => {
      let date = new Date(dateInput);
      const month = date.getMonth() + 1;
      if (month <= 3) return 'Q1';
      if (month <= 6) return 'Q2';
      if (month <= 9) return 'Q3';
      return 'Q4';
    };

    const dummyUseOfIndex = (index) => {
      console.log('Index used:', index);
    };

    // Date Picker Display Function
    const showDatePickerForField = (dateField, index) => {
      if (!dateField) {
        console.error(`dateField is undefined at index: ${index}`);
        return;
      }

      if (!dateField.selectedDate) {
        dateField.selectedDate = new Date();
        console.log(`Initialized selectedDate for index ${index} to today:`, dateField.selectedDate);
      }

      dateField.showDatePicker = true;
      console.log(`Showing date picker for field at index: ${index}`);
    };

    // Persistence Loading Function
    const loadPersistedValues = () => {
      console.log('Loading persisted values from Vuex...');

      // Log Vuex state before assignment
      console.log('Vuex dynamicInputs:', store.state.dynamicInputs);
      console.log('Vuex dropdownMenus:', store.state.dropdownMenus);
      console.log('Vuex dynamicDateFields:', store.state.dynamicDateFields);

      // Clear local states to force reactivity
      dynamicInputs.value = [];
      dropdownMenus.value = [];
      dynamicDateFields.value = [];

      // Populate dynamic input values
      dynamicInputs.value = store.state.dynamicInputs.map(input => ({
        ...input,
        value: store.state.dynamicInputs.find(stateInput => stateInput.id === input.id)?.value || '',
      }));

      // Merge selectedOption from dropdownMenus with options from fullDropdownMenus
      dropdownMenus.value = [...store.state.dropdownMenus];

      // Populate dynamic date fields
      dynamicDateFields.value = store.state.dynamicDateFields.map(dateField => {
        const persistedField = store.state.dynamicDateFields.find(stateDate => stateDate.id === dateField.id) || {};
        return {
          ...dateField,
          value: persistedField.value || '',
          year: persistedField.year || '',
          quarter: persistedField.quarter || '',
          showDatePicker: false,
          hyperlink: dateField.hyperlink || null, // Include hyperlink if exists
        };
      });

      // Log after assignment to verify the local state reflects Vuex data
      console.log('Local dynamicInputs after loading:', dynamicInputs.value);
      console.log('Local dropdownMenus after loading:', dropdownMenus.value);
      console.log('Local dynamicDateFields after loading:', dynamicDateFields.value);
    };

    // Data Loading Function
    const loadTemplateInputs = async () => {
      // Extract fileId and bucketName from the selectedTemplate object
      const { fileId, bucketName } = store.state.selectedTemplate;

      if (!fileId || !bucketName) {
        console.error('Selected template lacks fileId or bucketName.');
        alert('Invalid template selection. Please select a valid template.');
        router.push({ name: 'userOptionsPage' });
        return;
      }

      // Clear existing data
      dynamicInputs.value = [];
      dropdownMenus.value = [];
      dynamicDateFields.value = [];

      try {
        // Fetch template data using the new endpoint
        const response = await axios.get('/api/files/fetch-template-content', {
          params: {
            fileId: fileId,
            bucketName: bucketName,
          },
          responseType: 'arraybuffer', // Handle binary data
        });

        console.log('Fetched template file successfully:', response);

        // Parse the fetched template content
        const parsedData = await fetchTemplateAndParseData(response.data);
        const parsedDateFields = await fetchDateFields(response.data);

        // Set local state with parsed data
        dynamicInputs.value = parsedData.inputs || [];
        dropdownMenus.value = parsedData.dropdowns.map(dropdown => ({
          ...dropdown, // Includes id, options, and hyperlink if exists
          selectedOption: '', // Initialize selectedOption
        }));
        dynamicDateFields.value = parsedDateFields.map(dateField => ({
          ...dateField,
          value: '',
          year: '',
          quarter: '',
          selectedDate: null,
          showDatePicker: false,
          hyperlink: dateField.hyperlink || null, // Include hyperlink if exists
        }));

        // Dispatch updates to Vuex store
        store.dispatch('updateDynamicInputs', dynamicInputs.value);
        store.dispatch('updateDropdownMenus', dropdownMenus.value); // Store full dropdown data
        store.dispatch('setDynamicDateFields', dynamicDateFields.value);
      } catch (error) {
        console.error('Error fetching or parsing template:', error);
        alert('Failed to load dynamic input fields. Please try again later.');
      }
    };

    // Update Function for Date Fields
    const updateDynamicDateField = (dateField, index, newDate) => {
      if (!dateField) {
        console.error(`dateField is undefined at index: ${index}`);
        return;
      }

      if (!(newDate instanceof Date)) {
        console.error('Invalid date selected:', newDate);
        return;
      }

      const formattedDate = format(newDate, 'yyyy-MM-dd');
      dateField.value = formattedDate;
      dateField.year = getYear(formattedDate);
      dateField.quarter = getQuarter(formattedDate);
      dateField.showDatePicker = false;

      store.dispatch('updateDynamicDateField', dateField);
    };

    // Navigation Function
    const navigateToDynamicTablePage = () => {
      if (!allFieldsFilled.value) {
        alert('Please fill in all fields before proceeding.');
        return;
      }

      const dynamicData = dynamicInputs.value.map(input => ({
        id: input.id,
        value: input.value,
      }));

      const dropdownData = dropdownMenus.value.map(dropdown => ({
        id: dropdown.id,
        selectedOption: dropdown.selectedOption,
      }));

      const dateData = dynamicDateFields.value.map(dateField => ({
        id: dateField.id,
        value: dateField.value,
        year: dateField.year,
        quarter: dateField.quarter,
      }));

      // Log the final data before dispatching to Vuex
      console.log('Final dynamicData being sent to Vuex:', dynamicData);
      console.log('Final dropdownData being sent to Vuex:', dropdownData);
      console.log('Final dateData being sent to Vuex:', dateData);

      // Dispatch to Vuex
      store.dispatch('updateDynamicInputs', dynamicData);
      store.dispatch('updateDropdownMenus', dropdownData);
      store.dispatch('setDynamicDateFields', dateData);

      router.push({ name: 'dynamicTablePage' });
    };

    // Define the navigateTo function
    const navigateTo = (url) => {
      window.open(url, '_blank'); // Opens the link in a new tab
    };

    onMounted(async () => {
      const selectedTemplate = store.state.selectedTemplate;
      console.log("Checking selectedTemplate in onMounted:", store.state.selectedTemplate);

      // Redirect to UserOptionsPage if no template is selected
      if (!selectedTemplate) {
        router.push({ name: 'userOptionsPage' });
        return;
      }

      // Check if navigating back and Vuex already holds values
      const hasPersistedValues = store.state.dynamicInputs.length > 0 
        || store.state.dropdownMenus.length > 0 
        || store.state.dynamicDateFields.length > 0;

      if (!store.state.isNavigatingBack || !hasPersistedValues) {
        console.log("First time load or refresh: Fetching and loading template inputs...");
        await loadTemplateInputs();
      } else {
        console.log("Navigating back: Loading persisted values from Vuex...");
        loadPersistedValues(); // Populate fields with values from Vuex
      }

      store.commit('setNavigatingBack', false);
    });

    onBeforeRouteLeave((to, from, next) => {
      store.commit('setNavigatingBack', true);
      next();
    });

    // Return Bindings
    return {
      router,
      store,
      dynamicInputs,
      dropdownMenus,
      navigateToDynamicTablePage,
      formatDropdownLabel,

      // For dynamic date pickers
      dynamicDateFields,
      updateDynamicDateField,
      showDatePickerForField,
      dummyUseOfIndex,
      formatDateLabel,
      allFieldsFilled,
      inputErrors,
      dropdownErrors,
      dateErrors,

      // New Method
      navigateTo,
    };
  },
};
</script>

<style scoped>
.main-content {
  padding-top: 64px; /* Adjusted based on the actual height of the v-app-bar */
  margin: 0; /* Remove any margin to avoid extra spacing */
}

.v-container {
  padding-top: 16px; /* Adjust the padding inside the container */
}

/* Container for input fields with hyperlinks */
.input-field-container,
.dropdown-field-container,
.date-field-container {
  display: flex;
  align-items: center;
  margin-bottom: 16px;
}

.hyperlink-button {
  margin-left: 8px;
}
</style>
